SELECT ps.product_id AS productId, p.name AS productName, p.spec AS spec, p.unit AS unit, p.category_id AS categoryId, c.name AS categoryName, ps.supply_price AS supplyPrice, p.stock AS stock, (SELECT COUNT(*) FROM pms_product_supplier ps2 WHERE ps2.enterprise_id = #{enterpriseId} AND ps2.product_id = ps.product_id AND ps2.is_deleted = 0) AS supplierCount FROM pms_product_supplier ps JOIN pms_product p ON p.id = ps.product_id AND p.is_deleted = 0 LEFT JOIN pms_category c ON c.id = p.category_id AND c.is_deleted = 0 WHERE ps.enterprise_id = #{enterpriseId} AND ps.supplier_id = #{supplierId} AND ps.is_deleted = 0
AND p.name LIKE CONCAT('%', #{keyword}, '%')
AND p.category_id = #{categoryId}
ORDER BY ps.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM pms_product_supplier ps
JOIN pms_product p
  ON p.id = ps.product_id AND p.is_deleted = 0
WHERE ps.enterprise_id = #{enterpriseId}
  AND ps.supplier_id   = #{supplierId}
  AND ps.is_deleted    = 0
  
    AND p.name LIKE CONCAT('%', #{keyword}, '%')
  
  
    AND p.category_id = #{categoryId}

SELECT COUNT(*)
FROM pms_product_supplier
WHERE enterprise_id = #{enterpriseId}
  AND product_id    = #{productId}
  AND is_deleted    = 0
